import { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useInAppNavigate } from '../../../../../router/useInAppNavigate';
import { dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../../../store/hooks';
import { useUnsavedChangesGuard } from '../../../../../hooks/useUnsavedChangesGuard';
import { useVoucherInitData } from '../../../../../hooks/useVoucherInitData';
import { ktService } from '../../../../../services/kt/ktService';
import type { VoucherStatus } from '../../../../../services/kt/models';
import { createSupplierSearchConfig } from '../../../../../components/search';
import { getApiErrorMessage } from '../../../../../utils/getApiErrorMessage';
import { pollDocumentPostingStatus } from '../../../../../utils/pollDocumentPostingStatus';
import {
  buildVoucherCopyNavigateState,
  buildVoucherSearchNavigateState,
  useVoucherFormRoute,
} from '../../../../../components/voucher';
import { resolveProcessingLevelSelectOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import {
  resolveVoucherCurrencyDefaults,
  resolveVoucherCurrencyFromDto,
} from '../../../../../utils/voucherCurrencyDefaults';
import { useApplyVoucherAccountDefaultOnce, type AccountDefault } from '../../../../../utils/voucherAccountDefaults';
import {
  buildVoucherToolbarDisabledReasons,
  isVoucherFormStatusLocked,
} from '../../../../../utils/voucherProcessingLevelDisplay';
import { canViewVoucherLedgerFromForm } from '../../../../../utils/voucherListRowActions';
import {
  FormMode,
  effectiveFormMode,
  initialFormMode,
  isEditingMode,
  isViewMode,
  useFormFieldLock,
  useFormRouteId,
} from '../../../../../components/form';
import { getPurchaseInvoiceConfig } from '../config/purchaseInvoiceConfig';
import {
  buildPurchaseInvoicePayload,
  buildSnapshotFromFields,
  lineAmount,
  lineTax,
  mapDtoToPurchaseInvoiceSnapshot,
  purchaseInvoiceSnapshotsEqual,
  serializePurchaseInvoiceSnapshot,
  toPurchaseInvoiceDateInputValue,
  type PurchaseInvoiceSnapshot,
} from '../mappers/purchaseInvoiceMappers';
