import {
  collectPurchaseInvoiceBannerMessages,
  validatePurchaseInvoiceForm,
} from './usePurchaseInvoiceValidate';
import { applyInlineValidationMessage } from '../../../../../utils/voucherFieldValidation';
import styles from '../../../../../styles/documentForm.module.css';

const blankLineDefaults = (
  defaultUnitCode: string,
  unitName: string,
  defaultTaxRate: number,
  defaultDebitAccount?: AccountDefault | null,
): PurchaseInvoiceLineRow => ({
  materialCode: '',
  materialName: '',
  unitCode: defaultUnitCode,
  unitName,
  quantity: 1,
  unitPrice: 0,
  taxRate: defaultTaxRate,
  debitAccountCode: defaultDebitAccount?.code ?? '',
  debitAccountName: defaultDebitAccount?.name ?? '',
});

function insertPurchaseInvoiceLineFieldErrors(
  lines: PurchaseInvoiceFieldErrors['lines'],
  insertAt: number,
): PurchaseInvoiceFieldErrors['lines'] | undefined {
  if (!lines) return undefined;
  const next: Record<number, PurchaseInvoiceLineFieldErrors> = {};
  Object.keys(lines).forEach(key => {
    const i = Number(key);
    const newIdx = i >= insertAt ? i + 1 : i;
    next[newIdx] = lines[i];
  });
  return Object.keys(next).length > 0 ? next : undefined;
}

function shiftPurchaseInvoiceLineFieldErrors(
  lines: PurchaseInvoiceFieldErrors['lines'],
  removedIndex: number,
): PurchaseInvoiceFieldErrors['lines'] | undefined {
  if (!lines) return undefined;
  const next: Record<number, PurchaseInvoiceLineFieldErrors> = {};
  Object.keys(lines).forEach(key => {
    const i = Number(key);
    if (i === removedIndex) return;
    const newIdx = i > removedIndex ? i - 1 : i;
    next[newIdx] = lines[i];
  });
  return Object.keys(next).length > 0 ? next : undefined;
}

export function usePurchaseInvoiceFormController({
  title,
  voucherCode,
  listPath,
}: PurchaseInvoiceFormProps) {
  const cfg = useMemo(
    () => getPurchaseInvoiceConfig(voucherCode, listPath, title),
    [voucherCode, listPath, title],
  );
  const id = useFormRouteId();
  const isNew = !id;
  const navigate = useInAppNavigate();
  const location = useLocation();
  const dispatch = useAppDispatch();

  const [invoiceDate, setInvoiceDate] = useState(new Date().toISOString().slice(0, 10));
  const [code, setCode] = useState('');
  const [supplierId, setSupplierId] = useState('');
  const [supplierCode, setSupplierCode] = useState('');
  const [supplierName, setSupplierName] = useState('');
  const [eInvoiceNo, setEInvoiceNo] = useState('');
  const [description, setDescription] = useState('');
  const [creditAccountCode, setCreditAccountCode] = useState('');
  const [creditAccountName, setCreditAccountName] = useState('');
  const [vatAccountCode, setVatAccountCode] = useState('');
  const [vatAccountName, setVatAccountName] = useState('');
  const [status, setStatus] = useState<VoucherStatus>('Draft');
  const [processingLevel, setProcessingLevel] = useState('');
  const [formMode, setFormMode] = useState<FormMode>(initialFormMode(isNew));
  const [currencyCode, setCurrencyCode] = useState('VND');
  const [exchangeRate, setExchangeRate] = useState(1);
  const [lines, setLines] = useState<PurchaseInvoiceLineRow[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [approving, setApproving] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [showPostModal, setShowPostModal] = useState(false);
  const [posting, setPosting] = useState(false);
  const [postingStatus, setPostingStatus] = useState<string>('None');
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [showSearchSlideout, setShowSearchSlideout] = useState(false);
  const [searchResultIds, setSearchResultIds] = useState<string[]>([]);
  const [savedSnapshot, setSavedSnapshot] = useState<string | null>(null);
  const [fieldErrors, setFieldErrors] = useState<PurchaseInvoiceFieldErrors>({});
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [bannerExpanded, setBannerExpanded] = useState(true);
  const [bannerClosed, setBannerClosed] = useState(false);
  const [headerExpanded, setHeaderExpanded] = useState(true);
  const [selectedLineIndex, setSelectedLineIndex] = useState(0);
  const [highlightLineIndex, setHighlightLineIndex] = useState<number | null>(null);
  const [accountingPeriods, setAccountingPeriods] = useState<AccountingPeriodGate[]>([]);
  const expandHeaderAfterSaveRef = useRef(false);
  /** Pattern B — inline errors only after first Lưu attempt. */
  const validationAttemptedRef = useRef(false);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      ktService.getPeriods()
        .then(periods => { if (!cancelled) setAccountingPeriods(periods); })
        .catch(() => { /* BE validates on save */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  const supplierSearchConfig = useMemo(() => createSupplierSearchConfig(), []);
  const initFormName = isNew ? 'create-purchase-invoice' : 'edit-purchase-invoice';
  const {
    taxRateOptions,
    currencyOptions,
    unitOptions,
    processingLevelOptions,
    defaultProcessingLevel,
    defaultCreditAccount,
    defaultVatAccount,
    defaultDebitAccount,
    defaultCurrencyCode,
    defaultExchangeRate,
    formPermissions,
  } = useVoucherInitData(initFormName);

  const processingOpts = useMemo(
    () => resolveProcessingLevelSelectOptions(processingLevelOptions, defaultProcessingLevel),
    [processingLevelOptions, defaultProcessingLevel],
  );

  const defaultUnitCode = useMemo(() => String(unitOptions[0]?.value ?? ''), [unitOptions]);
  const defaultTaxRate = useMemo(
    () => Number(taxRateOptions[0]?.value ?? 10),
    [taxRateOptions],
  );

  useEffect(() => {
    if (!isNew) return;
    const { currencyCode: code, exchangeRate: rate } = resolveVoucherCurrencyDefaults(
      defaultCurrencyCode,
      defaultExchangeRate,
    );
    setCurrencyCode(code);
    setExchangeRate(rate);
  }, [isNew, defaultCurrencyCode, defaultExchangeRate]);

  useApplyVoucherAccountDefaultOnce(
    isNew,
    creditAccountCode,
    defaultCreditAccount,
    setCreditAccountCode,
    setCreditAccountName,
  );

  useApplyVoucherAccountDefaultOnce(
    isNew,
    vatAccountCode,
    defaultVatAccount,
    setVatAccountCode,
    setVatAccountName,
  );

  const resolveUnitName = useCallback(
    (unitCode?: string): string =>
      unitOptions.find(o => String(o.value) === String(unitCode ?? ''))?.label ?? '',
    [unitOptions],
  );

  const makeEmptyLine = useCallback(
    (): PurchaseInvoiceLineRow =>
      blankLineDefaults(defaultUnitCode, resolveUnitName(defaultUnitCode), defaultTaxRate, defaultDebitAccount),
    [defaultUnitCode, defaultTaxRate, defaultDebitAccount, resolveUnitName],
  );

  useEffect(() => {
    if (lines.length === 0) {
      setLines([makeEmptyLine()]);
    }
  }, [lines.length, makeEmptyLine]);

  useEffect(() => {
    if (!defaultUnitCode) return;
    setLines(prev => {
      if (prev.length !== 1 || prev[0].materialCode || prev[0].unitCode) return prev;
      return [makeEmptyLine()];
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps -- seed first blank line when init-data arrives
  }, [defaultUnitCode, defaultDebitAccount, taxRateOptions, makeEmptyLine]);

  const taxRateSelectOptions = useMemo(
    () => (taxRateOptions.length > 0 ? taxRateOptions : [{ value: '10', label: '10%' }]),
    [taxRateOptions],
  );

  const tid = (suffix: string) => `${cfg.testIdPrefix}-${suffix}`;
  const validationBannerId = tid('validation-banner');
  const toolbarMode = effectiveFormMode(isNew, formMode);
  const isStatusLocked = isVoucherFormStatusLocked(status, processingLevel);
  const showPostButton = false;

  useEffect(() => {
    if (highlightLineIndex == null) return undefined;
    const timer = window.setTimeout(() => setHighlightLineIndex(null), 2200);
    return () => window.clearTimeout(timer);
  }, [highlightLineIndex]);

  useEffect(() => {
    if (selectedLineIndex >= lines.length) {
      setSelectedLineIndex(Math.max(0, lines.length - 1));
    }
  }, [lines.length, selectedLineIndex]);

  const fieldLock = useFormFieldLock({
    formMode: toolbarMode,
    isStatusLocked,
    styles,
  });

  const resolveLevelForSave = useCallback((): string => {
    const raw =
      processingLevel.trim() ||
      (defaultProcessingLevel != null ? String(defaultProcessingLevel) : '') ||
      (processingOpts[0]?.value != null ? String(processingOpts[0].value) : '') ||
      '1';
    return String(raw);
  }, [processingLevel, defaultProcessingLevel, processingOpts]);

  const buildSnapshot = useCallback(
    (): PurchaseInvoiceSnapshot =>
      buildSnapshotFromFields({
        invoiceDate,
        supplierId,
        supplierCode,
        supplierName,
        eInvoiceNo,
        description,
        currencyCode,
        exchangeRate,
        creditAccountCode,
        vatAccountCode,
        processingLevel: resolveLevelForSave(),
        lines,
      }),
    [
      invoiceDate,
      supplierId,
      supplierCode,
      supplierName,
      eInvoiceNo,
      description,
      currencyCode,
      exchangeRate,
      creditAccountCode,
      vatAccountCode,
      resolveLevelForSave,
      lines,
    ],
  );

  const currentSerialized = useMemo(
    () => serializePurchaseInvoiceSnapshot(buildSnapshot()),
    [buildSnapshot],
  );

  const isDirty = isEditingMode(toolbarMode) && !purchaseInvoiceSnapshotsEqual(savedSnapshot, currentSerialized);

  const {
    showUnsavedModal,
    setShowUnsavedModal,
    guardedAction,
    confirmLeave,
    cancelLeave,
  } = useUnsavedChangesGuard(isDirty, isEditingMode(toolbarMode));

  const markSnapshotSaved = useCallback(() => {
    setSavedSnapshot(serializePurchaseInvoiceSnapshot(buildSnapshot()));
  }, [buildSnapshot]);

  const syncBannerFromFieldErrors = useCallback((fe: PurchaseInvoiceFieldErrors) => {
    setValidationErrors(collectPurchaseInvoiceBannerMessages(fe));
  }, []);

  const clearAllValidation = useCallback(() => {
    validationAttemptedRef.current = false;
    setFieldErrors({});
    setValidationErrors([]);
  }, []);

  const applySnapshot = useCallback(
    (snap: PurchaseInvoiceSnapshot, resetSaved: boolean) => {
      setInvoiceDate(snap.invoiceDate);
      setSupplierId(snap.supplierId);
      setSupplierCode(snap.supplierCode);
      setSupplierName(snap.supplierName);
      setEInvoiceNo(snap.eInvoiceNo);
      setDescription(snap.description ?? '');
      setCurrencyCode(snap.currencyCode || 'VND');
      setExchangeRate(snap.exchangeRate || 1);
      setCreditAccountCode(snap.creditAccountCode);
      setVatAccountCode(snap.vatAccountCode);
      setProcessingLevel(
        snap.processingLevel ||
          (defaultProcessingLevel != null ? String(defaultProcessingLevel) : '1'),
      );
      setLines(snap.lines.length > 0 ? snap.lines : [makeEmptyLine()]);
      if (resetSaved) {
        setStatus('Draft');
        setCode('');
        markSnapshotSaved();
      }
    },
    [makeEmptyLine, markSnapshotSaved, defaultProcessingLevel],
  );

  const applyDto = useCallback(
    (v: Awaited<ReturnType<typeof cfg.get>>) => {
      setInvoiceDate(toPurchaseInvoiceDateInputValue(v.invoiceDate));
      setCode(v.code);
      setSupplierId(v.supplierId);
      setSupplierName(v.supplierName);
      setSupplierCode('');
      if (v.supplierId) {
        ktService
          .getCustomer(v.supplierId)
          .then(c => {
            setSupplierCode(c.code);
            if (!v.supplierName) setSupplierName(c.name);
          })
          .catch(() => {});
      }
      setEInvoiceNo(v.eInvoiceNo ?? '');
      setDescription(v.description ?? '');
      setCreditAccountCode(v.creditAccountCode ?? '');
      setVatAccountCode(v.vatAccountCode ?? '');
      setCreditAccountName(v.creditAccountName ?? '');
      setVatAccountName(v.vatAccountName ?? '');
      const { currencyCode: code, exchangeRate: rate } = resolveVoucherCurrencyFromDto(
        v.currencyCode,
        v.exchangeRate,
        defaultCurrencyCode,
        defaultExchangeRate,
      );
      setCurrencyCode(code);
      setExchangeRate(rate);
      setStatus(v.status);
      setProcessingLevel(
        v.processingLevel ??
          (defaultProcessingLevel != null ? String(defaultProcessingLevel) : '1'),
      );
      const snap = mapDtoToPurchaseInvoiceSnapshot(v, resolveUnitName);
      setLines(snap.lines);
      setSavedSnapshot(serializePurchaseInvoiceSnapshot(snap));
      clearAllValidation();
    },
    [cfg, resolveUnitName, clearAllValidation, defaultProcessingLevel, defaultCurrencyCode, defaultExchangeRate],
  );

  const canViewLedgerToolbar = canViewVoucherLedgerFromForm({
    isNew,
    id,
    status,
    processingLevel,
    postingStatus,
    canViewLedgerPermission: formPermissions?.canViewLedger ?? false,
  });

  const reloadVoucherFromServer = useCallback(async (voucherId: string) => {
    const v = await cfg.get(voucherId);
    applyDto(v);
    setFormMode(FormMode.View);
  }, [cfg, applyDto]);

  const refreshPostingStatusAfterLevelChange = useCallback(async (
    previousLevel: string,
    newLevel: string,
    voucherId?: string,
  ) => {
    if (!voucherId) return;
    const wasAutoPost = previousLevel === '9';
    const isAutoPost = newLevel === '9';
    try {
      if (isAutoPost) {
        const ps = await cfg.getPostingStatus(voucherId);
        setPostingStatus(ps.postingStatus);
        if (ps.postingStatus === 'Queued' || ps.postingStatus === 'Processing') {
          const final = await pollDocumentPostingStatus(() => cfg.getPostingStatus(voucherId));
          setPostingStatus(final.postingStatus);
          if (final.postingStatus === 'Failed' && final.lastError) {
            dispatchAppToast(dispatch, { message: final.lastError, type: 'error' });
          }
          if (final.postingStatus === 'Posted') {
            await reloadVoucherFromServer(voucherId);
          }
        } else if (ps.postingStatus === 'Posted') {
          await reloadVoucherFromServer(voucherId);
        }
      } else if (wasAutoPost && !isAutoPost) {
        const final = await pollDocumentPostingStatus(() => cfg.getPostingStatus(voucherId));
        setPostingStatus(final.postingStatus);
        if (final.postingStatus === 'Failed' && final.lastError) {
          dispatchAppToast(dispatch, { message: final.lastError, type: 'error' });
          return;
        }
        await reloadVoucherFromServer(voucherId);
      }
    } catch {
      /* optional */
    }
  }, [cfg, dispatch, reloadVoucherFromServer]);

  useEffect(() => {
    if (isNew || !id) {
      setPostingStatus('None');
      return;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      void (async () => {
        try {
          const ps = await cfg.getPostingStatus(id);
          if (!cancelled) setPostingStatus(ps.postingStatus);
        } catch {
          /* optional */
        }
      })();
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, isNew, cfg]);

  const resetEmptyForm = useCallback(() => {
    setInvoiceDate(new Date().toISOString().slice(0, 10));
    setCode('');
    setSupplierId('');
    setSupplierCode('');
    setSupplierName('');
    setEInvoiceNo('');
    setCreditAccountCode(defaultCreditAccount?.code ?? '');
    setCreditAccountName(defaultCreditAccount?.name ?? '');
    setVatAccountCode(defaultVatAccount?.code ?? '');
    setVatAccountName(defaultVatAccount?.name ?? '');
    const { currencyCode: code, exchangeRate: rate } = resolveVoucherCurrencyDefaults(
      defaultCurrencyCode,
      defaultExchangeRate,
    );
    setCurrencyCode(code);
    setExchangeRate(rate);
    setStatus('Draft');
    setProcessingLevel(
      defaultProcessingLevel != null
        ? String(defaultProcessingLevel)
        : String(processingOpts[0]?.value ?? '1'),
    );
    setLines([makeEmptyLine()]);
    clearAllValidation();
  }, [makeEmptyLine, clearAllValidation, defaultProcessingLevel, processingOpts, defaultCurrencyCode, defaultExchangeRate, defaultCreditAccount, defaultVatAccount]);

  useEffect(() => {
    if (!isNew || processingLevel) return;
    const level =
      defaultProcessingLevel != null
        ? String(defaultProcessingLevel)
        : processingOpts[0]?.value != null
          ? String(processingOpts[0].value)
          : '';
    if (level) setProcessingLevel(level);
  }, [isNew, processingLevel, defaultProcessingLevel, processingOpts]);

  const closeOverlays = useCallback(() => {
    setShowSearchSlideout(false);
    setShowApproveModal(false);
    setShowPrintModal(false);
    setShowDeleteModal(false);
    setShowPostModal(false);
  }, []);

  const applyCopySnapshot = useCallback(
    (snap: PurchaseInvoiceSnapshot) => applySnapshot(snap, true),
    [applySnapshot],
  );

  const { copySourceVoucherCode } = useVoucherFormRoute<PurchaseInvoiceSnapshot>({
    isNew,
    id,
    location,
    navigate,
    setFormMode,
    setSearchResultIds,
    resetEmptyForm,
    applyCopySnapshot,
    initNewSavedSnapshot: markSnapshotSaved,
    onRouteChange: closeOverlays,
  });

  const patchHeaderFieldError = useCallback(
    (key: 'invoiceDate' | 'supplierId' | 'creditAccountCode' | 'vatAccountCode' | 'description', value: string) => {
      let rawError: string | undefined;
      if (key === 'invoiceDate') rawError = value.trim() ? undefined : 'Ngày hóa đơn là bắt buộc';
      if (key === 'supplierId') rawError = value.trim() ? undefined : 'Nhà cung cấp là bắt buộc';
      if (key === 'creditAccountCode') rawError = value.trim() ? undefined : 'TK Có (công nợ) là bắt buộc';
      if (key === 'vatAccountCode') rawError = value.trim() ? undefined : 'TK thuế GTGT là bắt buộc';
      if (key === 'description' && value.length > 4000) rawError = 'Diễn giải tối đa 4000 ký tự';
      const nextError = applyInlineValidationMessage(validationAttemptedRef.current, rawError);
      setFieldErrors(prev => {
        const next = { ...prev, [key]: nextError };
        if (!nextError) delete next[key];
        syncBannerFromFieldErrors(next);
        return next;
      });
    },
    [syncBannerFromFieldErrors],
  );

  const patchLineFieldError = useCallback(
    (
      idx: number,
      key: 'materialCode' | 'quantity' | 'unitPrice' | 'taxRate' | 'debitAccountCode',
      value: string | number,
    ) => {
      let rawError: string | undefined;
      if (key === 'materialCode') rawError = String(value).trim() ? undefined : `Dòng ${idx + 1}: chưa nhập mã vật tư`;
      if (key === 'quantity') rawError = Number(value) > 0 ? undefined : `Dòng ${idx + 1}: số lượng phải > 0`;
      if (key === 'unitPrice') rawError = Number(value) >= 0 ? undefined : `Dòng ${idx + 1}: đơn giá không hợp lệ`;
      if (key === 'taxRate') rawError = Number(value) >= 0 ? undefined : `Dòng ${idx + 1}: thuế suất không hợp lệ`;
      if (key === 'debitAccountCode') rawError = String(value).trim() ? undefined : `Dòng ${idx + 1}: chưa nhập TK Nợ`;
      const nextError = applyInlineValidationMessage(validationAttemptedRef.current, rawError);

      setFieldErrors(prev => {
        const linesMap = { ...(prev.lines ?? {}) };
        const row = { ...(linesMap[idx] ?? {}) };
        if (nextError) row[key] = nextError;
        else delete row[key];
        if (Object.keys(row).length === 0) delete linesMap[idx];
        else linesMap[idx] = row;
        const next: PurchaseInvoiceFieldErrors = { ...prev };
        if (Object.keys(linesMap).length === 0) delete next.lines;
        else next.lines = linesMap;
        syncBannerFromFieldErrors(next);
        return next;
      });
    },
    [syncBannerFromFieldErrors],
  );

  const scrollToFirstFieldError = useCallback(
    (fe: PurchaseInvoiceFieldErrors) => {
      const scroll = (elementId: string) => {
        setTimeout(() => {
          document.getElementById(elementId)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }, 120);
      };
      if (fe.invoiceDate) return scroll(tid('field-invoiceDate'));
      if (fe.supplierId) return scroll(tid('field-supplierId'));
      if (fe.creditAccountCode) return scroll(tid('field-creditAccountCode'));
      if (fe.vatAccountCode) return scroll(tid('field-vatAccountCode'));
      if (fe.lines) {
        const lineIndices = Object.keys(fe.lines).map(Number).sort((a, b) => a - b);
        for (const idx of lineIndices) {
          const lineErr = fe.lines[idx];
          if (lineErr?.materialCode) return scroll(tid(`line-${idx + 1}-material`));
          if (lineErr?.quantity) return scroll(tid(`line-${idx + 1}-quantity`));
          if (lineErr?.unitPrice) return scroll(tid(`line-${idx + 1}-unitPrice`));
          if (lineErr?.taxRate) return scroll(tid(`line-${idx + 1}-taxRate`));
          if (lineErr?.debitAccountCode) return scroll(tid(`line-${idx + 1}-debitAccountCode`));
        }
      }
      return scroll(validationBannerId);
    },
    [tid, validationBannerId],
  );

  useEffect(() => {
    if (isNew) {
      setFormMode(FormMode.Create);
      setStatus('Draft');
      return;
    }
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      cfg
        .get(id!)
        .then(v => {
          if (cancelled) return;
          applyDto(v);
          setFormMode(FormMode.View);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Không thể tải hóa đơn. Vui lòng thử lại.'),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [id, cfg, dispatch, isNew, applyDto]);

  const totalAmount = useMemo(
    () => lines.reduce((s, l) => s + lineAmount(l) + lineTax(l), 0),
    [lines],
  );

  const handleSave = async () => {
    validationAttemptedRef.current = true;
    const level = resolveLevelForSave();
    if (!level) {
      setValidationErrors(['Mức xử lý là bắt buộc']);
      setBannerClosed(false);
      setBannerExpanded(true);
      return;
    }
    const nextErrors = validatePurchaseInvoiceForm(
      invoiceDate,
      supplierId,
      creditAccountCode,
      vatAccountCode,
      lines,
    );
    const periodError = validateVoucherDateAgainstPeriods(invoiceDate, accountingPeriods);
    if (periodError) {
      nextErrors.invoiceDate = periodError;
    }
    if (Object.keys(nextErrors).length > 0 || lines.length === 0) {
      if (lines.length === 0) setValidationErrors(['Phải có ít nhất 1 dòng hàng']);
      setFieldErrors(nextErrors);
      syncBannerFromFieldErrors(nextErrors);
      setBannerClosed(false);
      setBannerExpanded(true);
      scrollToFirstFieldError(nextErrors);
      return;
    }
    setFieldErrors({});
    setValidationErrors([]);
    setSaving(true);
    try {
      const payload = buildPurchaseInvoicePayload(
        invoiceDate,
        voucherCode,
        supplierId,
        eInvoiceNo,
        description,
        currencyCode,
        exchangeRate,
        creditAccountCode,
        vatAccountCode,
        level,
        lines,
      );
      if (isNew) {
        const created = await ktService.createPurchaseInvoice(payload);
        dispatchAppToast(dispatch, { message: 'Tạo thành công', type: 'success' });
        expandHeaderAfterSaveRef.current = true;
        navigate(`${listPath}/${created.id}`);
        void refreshPostingStatusAfterLevelChange('', level, created.id);
      } else {
        const previousLevel = processingLevel;
        await ktService.updatePurchaseInvoice(id!, payload);
        dispatchAppToast(dispatch, { message: 'Cập nhật thành công', type: 'success' });
        setFormMode(FormMode.View);
        setHeaderExpanded(true);
        markSnapshotSaved();
        void refreshPostingStatusAfterLevelChange(previousLevel, level, id);
      }
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, 'Lưu thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  const handlePost = async () => {
    if (isNew || !id) return;
    setPosting(true);
    try {
      await ktService.postPurchaseInvoice(id);
      dispatchAppToast(dispatch, { message: 'Ghi sổ thành công', type: 'success' });
      setShowPostModal(false);
      const v = await cfg.get(id);
      applyDto(v);
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, 'Ghi sổ thất bại'), type: 'error' });
    } finally {
      setPosting(false);
    }
  };

  const handleApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    try {
      const level = newLevel.trim();
      if (!level) {
        dispatchAppToast(dispatch, { message: 'Mức xử lý là bắt buộc', type: 'error' });
        return;
      }
      const previousLevel = processingLevel;
      if (!isNew && id) {
        const payload = buildPurchaseInvoicePayload(
          invoiceDate,
          voucherCode,
          supplierId,
          eInvoiceNo,
          description,
          currencyCode,
          exchangeRate,
          creditAccountCode,
          vatAccountCode,
          level,
          lines,
        );
        await ktService.updatePurchaseInvoice(id, payload);
        setProcessingLevel(level);
        markSnapshotSaved();
        dispatchAppToast(dispatch, { message: 'Đã cập nhật mức xử lý', type: 'success' });
        void refreshPostingStatusAfterLevelChange(previousLevel, level, id);
      } else {
        setProcessingLevel(level);
        markSnapshotSaved();
        dispatchAppToast(dispatch, {
          message: 'Đã cập nhật mức xử lý (lưu cùng chứng từ khi ghi nhận)',
          type: 'success',
        });
      }
      setShowApproveModal(false);
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, 'Cập nhật mức xử lý thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  };

  const toolbarDisabledReasons = useMemo(
    () => buildVoucherToolbarDisabledReasons({ isNew, status, showPostButton, isStatusLocked }),
    [isNew, status, showPostButton, isStatusLocked],
  );

  const handleDelete = async () => {
    if (isNew || !id) return;
    setDeleting(true);
    try {
      await ktService.deletePurchaseInvoice(id);
      dispatchAppToast(dispatch, { message: 'Xóa thành công', type: 'success' });
      navigate(listPath);
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, 'Xóa thất bại'), type: 'error' });
    } finally {
      setDeleting(false);
      setShowDeleteModal(false);
    }
  };

  const revertToSaved = useCallback(() => {
    if (!savedSnapshot) return;
    const snap = JSON.parse(savedSnapshot) as PurchaseInvoiceSnapshot;
    applySnapshot(snap, false);
    clearAllValidation();
  }, [savedSnapshot, applySnapshot, clearAllValidation]);

  const handleBack = () =>
    guardedAction(() => {
      setSearchResultIds([]);
      navigate(listPath);
    });

  const handleCancel = () => {
    if (formMode === FormMode.Edit) {
      revertToSaved();
      setFormMode(FormMode.View);
      return;
    }
    if (isNew) {
      navigate(listPath);
      return;
    }
    setFormMode(FormMode.View);
    clearAllValidation();
  };

  const handleNew = () => guardedAction(() => navigate(`${listPath}/them`));
  const handleEdit = () => setFormMode(FormMode.Edit);
  const handleCopy = () => {
    guardedAction(() => {
      navigate(
        `${listPath}/them`,
        { state: buildVoucherCopyNavigateState(buildSnapshot(), code) },
      );
    });
  };

  const handleOpenFromSearch = (voucherId: string, resultIds: string[]) => {
    setSearchResultIds(resultIds);
    guardedAction(() =>
      navigate(`${listPath}/${voucherId}`, { state: buildVoucherSearchNavigateState(resultIds) }),
    );
  };

  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatchAppToast(dispatch, {
        message: `In PDF (placeholder) — mẫu: ${templateId}. Triển khai preview/PDF sau.`,
        type: 'info',
      });
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const searchNavIndex = id ? searchResultIds.indexOf(id) : -1;
  const hasSearchNav = searchNavIndex >= 0 && searchResultIds.length > 0;

  const navigateToSearchId = (targetId: string) => {
    guardedAction(() =>
      navigate(`${listPath}/${targetId}`, { state: buildVoucherSearchNavigateState(searchResultIds) }),
    );
  };

  useEffect(() => {
    if (!saving && expandHeaderAfterSaveRef.current) {
      setHeaderExpanded(true);
      expandHeaderAfterSaveRef.current = false;
    }
  }, [saving, id, formMode]);

  const insertLineAfter = useCallback(
    (afterIndex: number, model?: PurchaseInvoiceLineRow): number => {
      const newLine = model ?? makeEmptyLine();
      setLines(prev => {
        const next = [...prev];
        next.splice(afterIndex + 1, 0, newLine);
        return next;
      });
      return afterIndex + 1;
    },
    [makeEmptyLine],
  );

  const handleAddLine = () => {
    if (lines.length === 0) return;
    const afterIdx =
      selectedLineIndex >= 0 && selectedLineIndex < lines.length
        ? selectedLineIndex
        : lines.length - 1;
    const insertAt = insertLineAfter(afterIdx);
    setFieldErrors(prev => {
      const shifted = insertPurchaseInvoiceLineFieldErrors(prev.lines, insertAt);
      const next = { ...prev };
      if (shifted) next.lines = shifted;
      else delete next.lines;
      syncBannerFromFieldErrors(next);
      return next;
    });
    setSelectedLineIndex(insertAt);
    setHighlightLineIndex(insertAt);
  };

  const handleCopyLine = () => {
    if (lines.length === 0) return;
    const afterIdx =
      selectedLineIndex >= 0 && selectedLineIndex < lines.length
        ? selectedLineIndex
        : lines.length - 1;
    const source = lines[afterIdx];
    if (!source) return;
    const insertAt = insertLineAfter(afterIdx, { ...source });
    setFieldErrors(prev => {
      const shifted = insertPurchaseInvoiceLineFieldErrors(prev.lines, insertAt);
      const next = { ...prev };
      if (shifted) next.lines = shifted;
      else delete next.lines;
      syncBannerFromFieldErrors(next);
      return next;
    });
    setSelectedLineIndex(insertAt);
    setHighlightLineIndex(insertAt);
  };

  const handleSelectLine = (idx: number) => setSelectedLineIndex(idx);

  const addLine = () => handleAddLine();
  const removeLine = (idx: number) => {
    if (lines.length <= 1) {
      dispatchAppToast(dispatch, { message: 'Phải có ít nhất 1 dòng', type: 'warning' });
      return;
    }
    setLines(prev => prev.filter((_, i) => i !== idx));
    setFieldErrors(prev => {
      const shifted = shiftPurchaseInvoiceLineFieldErrors(prev.lines, idx);
      const next: PurchaseInvoiceFieldErrors = { ...prev };
      if (shifted) next.lines = shifted;
      else delete next.lines;
      syncBannerFromFieldErrors(next);
      return next;
    });
    setSelectedLineIndex(prev => {
      if (prev > idx) return prev - 1;
      if (prev === idx) return Math.max(0, idx - 1);
      return prev;
    });
    if (highlightLineIndex === idx) setHighlightLineIndex(null);
  };

  const updateLine = (idx: number, patch: Partial<PurchaseInvoiceLineRow>) => {
    setLines(prev => prev.map((l, i) => (i === idx ? { ...l, ...patch } : l)));
    if (patch.materialCode !== undefined) patchLineFieldError(idx, 'materialCode', patch.materialCode);
    if (patch.quantity !== undefined) patchLineFieldError(idx, 'quantity', patch.quantity);
    if (patch.unitPrice !== undefined) patchLineFieldError(idx, 'unitPrice', patch.unitPrice);
    if (patch.taxRate !== undefined) patchLineFieldError(idx, 'taxRate', patch.taxRate);
    if (patch.debitAccountCode !== undefined) patchLineFieldError(idx, 'debitAccountCode', patch.debitAccountCode);
  };

  return {
    cfg,
    title,
    isNew,
    id,
    code,
    status,
    toolbarMode,
    isStatusLocked,
    isViewMode: isViewMode(toolbarMode),
    showInitialLoading: loading,
    saving,
    approving,
    posting,
    printing,
    deleting,
    processingLevel,
    setProcessingLevel,
    processingOpts,
    showPostButton,
    toolbarDisabledReasons,
    formPermissions,
    showDeleteModal,
    setShowDeleteModal,
    showApproveModal,
    setShowApproveModal,
    showPostModal,
    setShowPostModal,
    handlePost,
    showLedgerModal,
    setShowLedgerModal,
    canViewLedger: canViewLedgerToolbar,
    postingStatus,
    showPrintModal,
    setShowPrintModal,
    showSearchSlideout,
    setShowSearchSlideout,
    showUnsavedModal,
    setShowUnsavedModal,
    cancelLeave,
    confirmLeave,
    validationErrors,
    bannerExpanded,
    bannerClosed,
    setBannerExpanded,
    setBannerClosed,
    validationBannerId,
    tid,
    styles,
    fieldLock,
    supplierSearchConfig,
    invoiceDate,
    setInvoiceDate,
    eInvoiceNo,
    setEInvoiceNo,
    description,
    setDescription,
    currencyCode,
    currencyOptions,
    exchangeRate,
    supplierId,
    supplierCode,
    supplierName,
    setSupplierId,
    setSupplierCode,
    setSupplierName,
    creditAccountCode,
    creditAccountName,
    vatAccountCode,
    vatAccountName,
    setCreditAccountCode,
    setCreditAccountName,
    setVatAccountCode,
    setVatAccountName,
    fieldErrors,
    patchHeaderFieldError,
    lines,
    taxRateSelectOptions,
    totalAmount,
    resolveUnitName,
    updateLine,
    addLine,
    handleAddLine,
    handleCopyLine,
    handleSelectLine,
    selectedLineIndex,
    highlightLineIndex,
    removeLine,
    headerExpanded,
    setHeaderExpanded,
    handleBack,
    handleSave,
    handleCancel,
    handleApproveConfirm,
    handleDelete,
    handleNew,
    handleEdit,
    handleCopy,
    handleOpenFromSearch,
    handlePrintConfirm,
    hasSearchNav,
    searchNavIndex,
    searchResultIds,
    navigateToSearchId,
    setFormMode,
    navigate,
    listPath,
    saveLabel: isNew ? 'Tạo mới' : 'Lưu thay đổi',
    copySourceVoucherCode,
  };
}
